#!/usr/bin/env python3 # -*- coding: utf-8 -*- """ Direct Snov.io REST API wrapper — no MCP server needed. Use when MCP is unavailable or you prefer direct API calls.  All Snov.io v1/v2 endpoints used by foreign-trade-prospecting.  Setup:     export SNOVIO_CLIENT_ID=your_id     export SNOVIO_CLIENT_SECRET=your_secret  Quick test:     python snovio_api.py balance  Usage examples:     python snovio_api.py find-email --first John --last Smith --domain acme.com     python snovio_api.py verify john@acme.com     python snovio_api.py domain-search "LED lighting California" --limit 20     python snovio_api.py domain-prospects acme.com --job procurement     python snovio_api.py company-info acme.com     python snovio_api.py balance """  import os import sys import json import time import argparse import urllib.request import urllib.error import urllib.parse  BASE = "https://api.snov.io" CLIENT_ID = os.environ.get("SNOVIO_CLIENT_ID", "") CLIENT_SECRET = os.environ.get("SNOVIO_CLIENT_SECRET", "")  ACCESS_TOKEN = None TOKEN_EXPIRES = 0   def _error(message):     """Print error to stderr and return error dict."""     print(f"[ERROR] {message}", file=sys.stderr)     return {"error": True, "message": message}   def get_token():     """Obtain or refresh OAuth access token."""     global ACCESS_TOKEN, TOKEN_EXPIRES     if ACCESS_TOKEN and time.time() < TOKEN_EXPIRES:         return ACCESS_TOKEN      if not CLIENT_ID or not CLIENT_SECRET:         raise RuntimeError(             "SNOVIO_CLIENT_ID and SNOVIO_CLIENT_SECRET not set.\n"             "  export SNOVIO_CLIENT_ID=your_id\n"             "  export SNOVIO_CLIENT_SECRET=your_secret\n"             "  Get them from: https://app.snov.io > Account Settings > API"         )      data = json.dumps({         "grant_type": "client_credentials",         "client_id": CLIENT_ID,         "client_secret": CLIENT_SECRET     }).encode("utf-8")      req = urllib.request.Request(         f"{BASE}/v1/oauth/access_token",         data=data,         headers={"Content-Type": "application/json"}     )      try:         resp = json.loads(urllib.request.urlopen(req, timeout=15).read())         ACCESS_TOKEN = resp["access_token"]         TOKEN_EXPIRES = time.time() + resp.get("expires_in", 3600) - 60         return ACCESS_TOKEN     except urllib.error.HTTPError as e:         body = e.read().decode()[:300]         raise RuntimeError(f"Auth failed ({e.code}): {body}")   def api(method, path, params=None, body=None):     """Call Snov.io API with automatic token management."""     token = get_token()     url = f"{BASE}{path}"     if params:         url += "?" + urllib.parse.urlencode(params, doseq=True)      data = None     if body is not None:         data = json.dumps(body).encode("utf-8")      req = urllib.request.Request(         url,         method=method,         data=data,         headers={             "Authorization": f"Bearer {token}",             "Content-Type": "application/json"         }     )      try:         resp = urllib.request.urlopen(req, timeout=30)         return json.loads(resp.read())     except urllib.error.HTTPError as e:         body_text = e.read().decode()[:300]         code = e.code         if code == 401:             global ACCESS_TOKEN, TOKEN_EXPIRES             ACCESS_TOKEN = None             TOKEN_EXPIRES = 0             return _error("Token expired. Retrying...")         elif code == 403:             return _error(f"API key invalid or insufficient permissions: {body_text}")         elif code == 429:             retry_after = e.headers.get("Retry-After", "60")             return _error(f"Rate limited. Retry after {retry_after}s. {body_text}")         else:             return _error(f"HTTP {code}: {body_text}")     except Exception as e:         return _error(f"Network error: {str(e)}")   # ======================================== # High-level API wrappers # ========================================  def get_balance():     """Check Snov.io credit balance."""     return api("GET", "/v1/get-balance")   def find_email(first, last, domain):     """Find email for a specific person."""     return api("GET", "/v1/get-emails", {         "firstName": first,         "lastName": last,         "domain": domain     })   def find_email_by_name(full_name, domain):     """Find email using full name (auto-split first/last)."""     parts = full_name.strip().split()     first = parts[0]     last = parts[-1] if len(parts) > 1 else ""     return find_email(first, last, domain)   def verify_email(email):     """Verify a single email address."""     return api("GET", "/v1/get-emails-verification-status", {         "emails[]": email     })   def verify_emails_batch(emails):     """Verify multiple emails at once (max 100 per call)."""     if len(emails) > 100:         return _error("Max 100 emails per batch call")     params = [("emails[]", e) for e in emails]     return api("GET", "/v1/get-emails-verification-status", params=params)   def domain_search(query, limit=20, start=0):     """     Search for companies by name/keyword.     Uses Snov.io v2 domain search endpoint.     """     payload = {         "domainName": query,         "limit": limit,         "start": start     }     return api("POST", "/v2/domain-search", body=payload)   def domain_prospects(domain, job_position=None, limit=20, offset=0):     """     Find prospects (contacts) at a specific domain.     Optionally filter by job position keywords.     """     payload = {         "domain": domain,         "limit": limit,         "offset": offset     }     if job_position:         payload["jobPosition"] = job_position     return api("POST", "/v1/domain-prospects", body=payload)   def company_info(domain):     """Get detailed company information by domain."""     return api("GET", "/v2/company-info", {         "domain": domain     })   def company_info_name(name):     """Get company information by name."""     return api("GET", "/v2/company-info", {         "name": name     })   def get_prospect_list(list_id=None):     """Get prospect lists (or specific list by ID)."""     if list_id:         return api("GET", f"/v1/prospects/{list_id}")     return api("GET", "/v1/prospects")   def add_to_list(list_id, prospects):     """Add prospects to a list. prospects = list of {email, first_name, last_name, ...}."""     payload = {         "listId": list_id,         "prospects": prospects     }     return api("POST", "/v1/prospects", body=payload)   # ======================================== # CLI # ========================================  def print_json(data):     """Pretty print JSON."""     print(json.dumps(data, indent=2, ensure_ascii=False))   def print_result_table(data, cmd):     """Format results as a readable table for common commands."""     if cmd == "balance":         if "data" in data:             d = data["data"]             credits = d.get("balance", "N/A")             print(f"  Balance: {credits} credits")         else:             print_json(data)         return      if cmd in ("find-email", "find-email-by-name"):         if "status" not in data or data["status"] != "complete":             print(f"  Status: {data.get('status', 'unknown')}")             print_json(data)             return         emails = data.get("data", {}).get("emails", [])         print(f"{'Email':40s} {'Status':10s} {'Confidence':>10s}")         print("-" * 62)         for e in emails:             status = e.get("emailStatus", "N/A")             conf = e.get("confidence", "")             print(f"{e.get('email',''):40s} {status:10s} {str(conf):>10s}")         return      if cmd == "domain-search":         companies = data.get("data", {}).get("companies", [])         if not companies:             print("  No companies found.")             return         print(f"{'Domain':30s} {'Company':30s} {'Industry':20s}")         print("-" * 82)         for c in companies:             domain_name = c.get("domain", "")             company = c.get("companyName", c.get("name", ""))             industry = c.get("industry", "")             print(f"{domain_name:30s} {company:30s} {industry:20s}")         return      if cmd == "domain-prospects":         prospects = data.get("data", {}).get("prospects", [])         if not prospects:             print("  No prospects found.")             return         print(f"{'Name':25s} {'Title':30s} {'Email':35s}")         print("-" * 92)         for p in prospects:             name = f"{p.get('firstName','')} {p.get('lastName','')}"             title = p.get("position", p.get("jobTitle", ""))             emails = [e.get("email","") for e in p.get("emails", [])]             email = emails[0] if emails else ""             print(f"{name:25s} {title:30s} {email:35s}")         return      if cmd == "verify":         status = data.get("data", [{}])[0] if data.get("data") else data         status_map = {             0: "waiting", 1: "valid", 2: "invalid",             3: "catch_all", 4: "disposable"         }         st = status_map.get(status.get("emailStatus", -1), "unknown")         print(f"  {status.get('email','')}: {st}")         return      if cmd == "company-info":         info = data.get("data", {})         print(f"  Name:     {info.get('companyName', info.get('name', 'N/A'))}")         print(f"  Domain:   {info.get('domain', 'N/A')}")         print(f"  Industry: {info.get('industry', 'N/A')}")         print(f"  Size:     {info.get('companySize', 'N/A')}")         print(f"  Country:  {info.get('country', info.get('location', 'N/A'))}")         print(f"  Revenue:  {info.get('revenue', 'N/A')}")         return      # Default: JSON     print_json(data)   def main():     parser = argparse.ArgumentParser(         description="Snov.io Direct API — no MCP needed",         formatter_class=argparse.RawDescriptionHelpFormatter,         epilog=""" Examples:   python snovio_api.py balance   python snovio_api.py find-email --first John --last Smith --domain acme.com   python snovio_api.py verify john@acme.com   python snovio_api.py domain-search "LED lighting"   python snovio_api.py domain-prospects acme.com --job procurement   python snovio_api.py company-info acme.com         """     )     sub = parser.add_subparsers(dest="command", help="Command to run")      # balance     sub.add_parser("balance", help="Check credit balance")      # find-email     fe = sub.add_parser("find-email", help="Find email by name + domain")     fe.add_argument("--first", required=True)     fe.add_argument("--last", required=True)     fe.add_argument("--domain", required=True)      # find-email-by-name     fen = sub.add_parser("find-email-by-name", help="Find email by full name + domain")     fen.add_argument("name", help="Full name (auto-split first/last)")     fen.add_argument("domain")      # verify     v = sub.add_parser("verify", help="Verify single email")     v.add_argument("email")      # verify-batch     vb = sub.add_parser("verify-batch", help="Verify multiple emails")     vb.add_argument("emails", nargs="+", help="Space-separated email list")      # domain-search     ds = sub.add_parser("domain-search", help="Search companies by keyword")     ds.add_argument("query", nargs="+", help="Search keywords")     ds.add_argument("--limit", type=int, default=20)     ds.add_argument("--start", type=int, default=0)      # domain-prospects     dp = sub.add_parser("domain-prospects", help="Find contacts at a domain")     dp.add_argument("domain")     dp.add_argument("--job", help="Job position filter")     dp.add_argument("--limit", type=int, default=20)     dp.add_argument("--offset", type=int, default=0)      # company-info     ci = sub.add_parser("company-info", help="Get company info by domain")     ci.add_argument("domain")      args = parser.parse_args()      if not args.command:         parser.print_help()         sys.exit(1)      # Check balance first for any paid operation     if args.command != "balance":         try:             bal = get_balance()             if not bal.get("error"):                 credits = bal.get("data", {}).get("balance", "OK")                 print(f"[Balance: {credits} credits]", file=sys.stderr)         except Exception:             pass      # Execute     if args.command == "balance":         result = get_balance()     elif args.command == "find-email":         result = find_email(args.first, args.last, args.domain)     elif args.command == "find-email-by-name":         result = find_email_by_name(args.name, args.domain)     elif args.command == "verify":         result = verify_email(args.email)     elif args.command == "verify-batch":         result = verify_emails_batch(args.emails)     elif args.command == "domain-search":         result = domain_search(" ".join(args.query), args.limit, args.start)     elif args.command == "domain-prospects":         result = domain_prospects(args.domain, args.job, args.limit, args.offset)     elif args.command == "company-info":         result = company_info(args.domain)     else:         parser.print_help()         sys.exit(1)      print_result_table(result, args.command)   if __name__ == "__main__":     main()  